import type { AdapterCapabilities, AdapterCategory, HealthMetrics } from '../../types/adapter';
import type {
  NormalizedFundingRate,
  NormalizedOpenInterest,
  NormalizedLiquidation,
} from '../../types/derivatives';
import type { ExchangeId } from '../../types/normalized';
import { RateLimiter } from '../../rate-limiter/rate-limiter';
import type {
  CoinglassApiResponse,
  CoinglassRawFundingRate,
  CoinglassRawOpenInterest,
  CoinglassRawLiquidation,
} from './coinglass-types';

const API_BASE = 'https://open-api-v3.coinglass.com/api';

/** Cache entry with expiration. */
interface CacheEntry<T> {
  data: T;
  expiresAt: number;
}

/**
 * Coinglass adapter for crypto derivatives analytics.
 *
 * Provides normalized access to funding rates, open interest, and liquidation
 * data aggregated across 30+ exchanges. Requires an API key for authentication.
 *
 * Rate limited to 80 calls per minute. Results are cached per symbol for 5
 * seconds to reduce API pressure during high-frequency access patterns.
 */
export class CoinglassAdapter {
  readonly exchangeId = 'coinglass' as const;
  readonly displayName = 'Coinglass';
  readonly category: AdapterCategory = 'data-provider';
  readonly capabilities: AdapterCapabilities = {
    realtime: false,
    historicalDepth: '1y',
    orderbook: false,
    trades: false,
    ohlcv: false,
    fundingRates: true,
    openInterest: true,
    liquidations: true,
    defiMetrics: false,
    onChainMetrics: false,
    authenticated: true,
  };

  private connected = false;
  private apiKey: string | null = null;
  private pollingInterval: ReturnType<typeof setInterval> | undefined;
  private rateLimiter: RateLimiter | null = null;
  private readonly cache = new Map<string, CacheEntry<unknown>>();

  private static readonly CACHE_TTL_MS = 5_000;
  private static readonly POLL_INTERVAL_MS = 30_000;

  /**
   * Connect to Coinglass and validate the API key.
   *
   * @param config.apiKey - Coinglass API key.
   * @throws If the API key is empty or validation fails.
   */
  async connect(config: { apiKey: string }): Promise<void> {
    if (this.connected) return;

    if (!config.apiKey || config.apiKey.trim().length === 0) {
      throw new Error('Coinglass API key is required');
    }

    this.apiKey = config.apiKey.trim();
    this.rateLimiter = new RateLimiter('coinglass', {
      maxTokens: 80,
      windowMs: 60_000,
      queueExcess: true,
      maxQueueDepth: 30,
    });

    // Validate the key by making a lightweight request
    await this.fetchJson<CoinglassRawFundingRate[]>('/futures/funding-rates?symbol=BTC');

    this.connected = true;
  }

  /** Disconnect and release resources. */
  async disconnect(): Promise<void> {
    if (!this.connected) return;
    this.connected = false;
    this.apiKey = null;
    if (this.pollingInterval !== undefined) {
      clearInterval(this.pollingInterval);
      this.pollingInterval = undefined;
    }
    this.cache.clear();
    if (this.rateLimiter) {
      this.rateLimiter.dispose();
      this.rateLimiter = null;
    }
  }

  /** Whether the adapter is connected with a valid API key. */
  isConnected(): boolean {
    return this.connected;
  }

  getHealthMetrics(): HealthMetrics {
    return {
      connected: this.connected,
      latencyMs: 0,
      messagesPerSecond: 0,
      uptimePercent: this.connected ? 100 : 0,
      lastMessageAt: 0,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  /**
   * Fetch current funding rates across exchanges for a symbol.
   *
   * Each exchange's funding rate is mapped to a NormalizedFundingRate with
   * the annualized rate calculated as `rate * 3 * 365` (3 funding periods
   * per day, 365 days per year).
   *
   * @param symbol - Trading pair symbol (e.g., "BTC", "ETH").
   */
  async getFundingRates(symbol: string): Promise<NormalizedFundingRate[]> {
    const cacheKey = `funding:${symbol}`;
    const cached = this.getCached<NormalizedFundingRate[]>(cacheKey);
    if (cached !== undefined) return cached;

    const raw = await this.fetchJson<CoinglassRawFundingRate[]>(
      `/futures/funding-rates?symbol=${encodeURIComponent(symbol)}`,
    );

    const now = Date.now();
    const results: NormalizedFundingRate[] = [];

    for (const entry of raw) {
      const exchangeId = this.mapExchangeId(entry.exchangeName);

      // Process U-margined entries
      if (entry.uMarginList) {
        for (const margin of entry.uMarginList) {
          results.push({
            symbol: `${symbol}/USDT`,
            exchangeId,
            rate: margin.rate,
            annualizedRate: margin.rate * 3 * 365,
            nextFundingTime: margin.nextFundingTime,
            timestamp: now,
          });
        }
      }

      // Process coin-margined entries
      if (entry.cMarginList) {
        for (const margin of entry.cMarginList) {
          results.push({
            symbol: `${symbol}/USD`,
            exchangeId,
            rate: margin.rate,
            annualizedRate: margin.rate * 3 * 365,
            nextFundingTime: margin.nextFundingTime,
            timestamp: now,
          });
        }
      }

      // If no margin lists, use the top-level rate
      if (!entry.uMarginList && !entry.cMarginList) {
        results.push({
          symbol: `${symbol}/USDT`,
          exchangeId,
          rate: entry.rate,
          annualizedRate: entry.rate * 3 * 365,
          nextFundingTime: entry.nextFundingTime,
          timestamp: now,
        });
      }
    }

    this.setCache(cacheKey, results, CoinglassAdapter.CACHE_TTL_MS);
    return results;
  }

  /**
   * Fetch current open interest across exchanges for a symbol.
   *
   * @param symbol - Trading pair symbol (e.g., "BTC", "ETH").
   */
  async getOpenInterest(symbol: string): Promise<NormalizedOpenInterest[]> {
    const cacheKey = `oi:${symbol}`;
    const cached = this.getCached<NormalizedOpenInterest[]>(cacheKey);
    if (cached !== undefined) return cached;

    const raw = await this.fetchJson<CoinglassRawOpenInterest[]>(
      `/futures/openInterest?symbol=${encodeURIComponent(symbol)}`,
    );

    const now = Date.now();
    const results: NormalizedOpenInterest[] = raw.map((entry) => ({
      symbol: `${symbol}/USDT`,
      exchangeId: this.mapExchangeId(entry.exchangeName),
      openInterest: entry.openInterestAmount,
      openInterestUsd: entry.openInterest,
      change24h: entry.h24Change,
      timestamp: now,
    }));

    this.setCache(cacheKey, results, CoinglassAdapter.CACHE_TTL_MS);
    return results;
  }

  /**
   * Fetch recent liquidation data for a symbol.
   *
   * @param symbol - Trading pair symbol (e.g., "BTC", "ETH").
   * @param options.period - Time period for liquidation data.
   */
  async getLiquidations(
    symbol: string,
    options?: { period?: '1h' | '4h' | '12h' | '24h' },
  ): Promise<NormalizedLiquidation[]> {
    const period = options?.period ?? '24h';
    const cacheKey = `liq:${symbol}:${period}`;
    const cached = this.getCached<NormalizedLiquidation[]>(cacheKey);
    if (cached !== undefined) return cached;

    const raw = await this.fetchJson<CoinglassRawLiquidation[]>(
      `/futures/liquidation/chart?symbol=${encodeURIComponent(symbol)}&range=${period}`,
    );

    const results: NormalizedLiquidation[] = [];

    for (const entry of raw) {
      const exchangeId = this.mapExchangeId(entry.exchangeName);
      const baseSymbol = `${symbol}/USDT`;

      if (entry.longVolUsd > 0) {
        for (let i = 0; i < entry.longCount; i++) {
          results.push({
            symbol: baseSymbol,
            exchangeId,
            side: 'long',
            quantity: 0,
            price: 0,
            usdValue: entry.longVolUsd / entry.longCount,
            timestamp: entry.time,
          });
        }
        // If no individual count, emit a single aggregated entry
        if (entry.longCount === 0) {
          results.push({
            symbol: baseSymbol,
            exchangeId,
            side: 'long',
            quantity: 0,
            price: 0,
            usdValue: entry.longVolUsd,
            timestamp: entry.time,
          });
        }
      }

      if (entry.shortVolUsd > 0) {
        for (let i = 0; i < entry.shortCount; i++) {
          results.push({
            symbol: baseSymbol,
            exchangeId,
            side: 'short',
            quantity: 0,
            price: 0,
            usdValue: entry.shortVolUsd / entry.shortCount,
            timestamp: entry.time,
          });
        }
        if (entry.shortCount === 0) {
          results.push({
            symbol: baseSymbol,
            exchangeId,
            side: 'short',
            quantity: 0,
            price: 0,
            usdValue: entry.shortVolUsd,
            timestamp: entry.time,
          });
        }
      }
    }

    this.setCache(cacheKey, results, CoinglassAdapter.CACHE_TTL_MS);
    return results;
  }

  private mapExchangeId(exchangeName: string): ExchangeId {
    const normalized = exchangeName.toLowerCase();
    const mapping: Record<string, ExchangeId> = {
      binance: 'binance',
      coinbase: 'coinbase',
      bybit: 'bybit',
      okx: 'okx',
    };
    return mapping[normalized] ?? ('custom' as ExchangeId);
  }

  private async fetchJson<T>(path: string): Promise<T> {
    if (!this.apiKey) {
      throw new Error('Coinglass adapter is not connected — call connect() first');
    }

    if (this.rateLimiter) {
      await this.rateLimiter.acquire();
    }

    const url = `${API_BASE}${path}`;
    const response = await fetch(url, {
      method: 'GET',
      headers: {
        Accept: 'application/json',
        'CG-API-KEY': this.apiKey,
        coinglassSecret: this.apiKey,
      },
    });

    if (!response.ok) {
      const body = await response.text().catch(() => '');
      if (response.status === 401 || response.status === 403) {
        throw new Error(`Coinglass authentication failed: invalid API key`);
      }
      throw new Error(
        `Coinglass API error: ${response.status} ${response.statusText}${body ? ` — ${body}` : ''}`,
      );
    }

    const envelope = (await response.json()) as CoinglassApiResponse<T>;

    if (!envelope.success && envelope.code !== '0') {
      throw new Error(`Coinglass API error: ${envelope.msg} (code: ${envelope.code})`);
    }

    return envelope.data;
  }

  private getCached<T>(key: string): T | undefined {
    const entry = this.cache.get(key) as CacheEntry<T> | undefined;
    if (!entry) return undefined;
    if (Date.now() >= entry.expiresAt) {
      this.cache.delete(key);
      return undefined;
    }
    return entry.data;
  }

  private setCache<T>(key: string, data: T, ttlMs: number): void {
    this.cache.set(key, { data, expiresAt: Date.now() + ttlMs });
  }
}
